def wordBreak(s, wordDict):
    word_set = set(wordDict)
    memo = {}

    def dfs(start):
        # If already computed
        if start in memo:
            return memo[start]

        # If reached end → valid sentence
        if start == len(s):
            return [""]

        sentences = []

        for end in range(start + 1, len(s) + 1):
            word = s[start:end]

            if word in word_set:
                # Recurse for remaining string
                sub_sentences = dfs(end)

                for sub in sub_sentences:
                    # Avoid extra space at end
                    if sub:
                        sentences.append(word + " " + sub)
                    else:
                        sentences.append(word)

        memo[start] = sentences
        return sentences

    return dfs(0)

